SELECT species_id, MAX(size_max) AS max_size
FROM ecological_data
GROUP BY species_id;

SELECT src_d15N_AQ_mu
FROM isotopic_data
WHERE isotopic_data_id = 0;

SELECT AVG(trophic_level_fbase) AS average_fbase
FROM trophic_levels
WHERE trophic_level_id = 1;

SELECT carbon
FROM elemental_composition
WHERE carbon > -25.0;

SELECT ecological_data_id, AVG(trophic_level_fbase) AS average_trophic_level
FROM trophic_levels
GROUP BY ecological_data_id;
